function evaluate(input, state) {
  if (state.cooldown > 0) {
    state.cooldown -= 1;
    return false;
  }
  state.cooldown = input.cooldown;
  state.actions += 1;
  return true;
}

function evaluate(input, state) {
  const hasAllRequired = input.required.every((flag) => state.flags.includes(flag));
  if (!hasAllRequired) {
    return false;
  }
  if (!state.rewards.includes(input.reward)) {
    state.rewards.push(input.reward);
  }
  return true;
}

function evaluate(input, state) {
  let cumulative = 0;
  for (const option of input.options) {
    cumulative += option.weight;
    if (cumulative > input.roll) {
      return option.id;
    }
  }
  return input.options[input.options.length - 1].id;
}

function evaluate(input, state) {
  state.score += input.points;
  return state.score;
}

function evaluate(input, state) {
  state.hp = Math.min(state.hp + input.heal, state.maxHp);
  state.events.push('healed');
  return state.hp;
}

function evaluate(input, state) {
  if (!state.inventory.includes(input.item)) {
    state.inventory.push(input.item);
  }
  return state.inventory.length;
}
